import time
import subprocess
from codecs import ignore_errors
from threading import Timer

from select import error


class runShell():
    """
    IOTable     class to parse io config json file
    :param:     profile:     string, file path of the io configuration json file, default None
    :example:
                io_table = IOTable(pin_map, "/mix/hwio.json")
    """

    @classmethod
    def run_shell_with_timeout(cls, cmd, timeout=5):
        # print("os.getcwd run shell =", os.getcwd())
        # print("cmd =", cmd)
        p = subprocess.Popen(cmd, shell=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        timer = Timer(timeout, lambda process: process.kill(), [p])
        try:
            timer.start()
            # for line in iter(p.stdout.readline, b''):
            #     print(line.decode("utf-8"), end='')
            stdout, stderr = p.communicate(timeout=timeout)
            out = stdout.decode("gbk").strip()
            error = stderr.decode("gbk").strip()
            return_code = p.returncode
            return return_code, out, error
        except Exception as e:
            raise RuntimeError('run_shell_with_timeout-Exception:{}'.format(e))
        finally:
            timer.cancel()

